// ============================================================
// Search, Filter & Save Grants (All-in-One)
// ============================================================

const DEDUP_BATCH = 50;
const AI_BATCH = 30;
const items = $input.all();
const webhookData = $('search for proposal with query').first().json.body;
const searchId = webhookData.search_id;
const orgId = webhookData.org_id;
const searchQuery = webhookData.searchQuery;
const orgType = webhookData.orgType || 'Any';
const profitStatus = webhookData.profitStatus || 'Any';
const industry = webhookData.industry || 'Any';
const fundingCategory = webhookData.fundingCategory || 'Any';

const openAiKey = 'REPLACE_ME';

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
const supaHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal',
};
const supaReadHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
};

// Helper: write search_results row
async function writeSearchResult(data) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/search_results',
    headers: supaHeaders,
    body: JSON.stringify(data),
  });
}

// --- STEP 1: Batched Dedup Check ---
const allGrants = items.map(i => i.json).filter(g => {
  const oppNum = (g.oppNum || '').trim();
  const title = (g.title || '').trim();
  return oppNum || title;
});

const totalGrants = allGrants.length;

// Post initial status immediately so UI never shows "no results"
try {
  await writeSearchResult.call(this, {
    search_id: searchId,
    org_id: orgId,
    source_group: '__status__:checking',
    grant_data: { status: 'checking', stage_message: 'Found ' + totalGrants + ' grants. Checking for duplicates...' },
    is_complete: false,
  });
} catch(e) {}

const withOppNum = allGrants.filter(g => (g.oppNum || '').trim());
const titleOnly = allGrants.filter(g => !(g.oppNum || '').trim() && (g.title || '').trim());

const existingIds = new Set();
const existingTitles = new Set();

const dedupBatches = Math.ceil(withOppNum.length / DEDUP_BATCH);
const titleBatchCount = Math.ceil(titleOnly.length / DEDUP_BATCH);
const totalDedupBatches = dedupBatches + titleBatchCount;
let checkedSoFar = 0;

for (let d = 0; d < dedupBatches; d++) {
  const batch = withOppNum.slice(d * DEDUP_BATCH, (d + 1) * DEDUP_BATCH);
  checkedSoFar += batch.length;
  const ids = batch.map(g => '"' + (g.oppNum || '').trim().replace(/"/g, '') + '"').join(',');

  try {
    await writeSearchResult.call(this, {
      search_id: searchId,
      org_id: orgId,
      source_group: '__status__:checking',
      grant_data: { status: 'checking', stage_message: 'Checking duplicates — ' + checkedSoFar + ' of ' + totalGrants + ' grants...' },
      is_complete: false,
    });
  } catch(e) {}

  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/grants?source_id=in.(' + ids + ')&select=source_id',
      headers: supaReadHeaders,
    });
    if (Array.isArray(response)) {
      for (const r of response) {
        existingIds.add((r.source_id || '').trim());
      }
    }
  } catch(e) {}
}

for (let d = 0; d < titleBatchCount; d++) {
  const batch = titleOnly.slice(d * DEDUP_BATCH, (d + 1) * DEDUP_BATCH);
  checkedSoFar += batch.length;
  const titles = batch.map(g => '"' + (g.title || '').trim().replace(/"/g, '') + '"').join(',');

  try {
    await writeSearchResult.call(this, {
      search_id: searchId,
      org_id: orgId,
      source_group: '__status__:checking',
      grant_data: { status: 'checking', stage_message: 'Checking duplicates — ' + checkedSoFar + ' of ' + totalGrants + ' grants...' },
      is_complete: false,
    });
  } catch(e) {}

  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/grants?title=in.(' + titles + ')&select=title',
      headers: supaReadHeaders,
    });
    if (Array.isArray(response)) {
      for (const r of response) {
        existingTitles.add((r.title || '').trim());
      }
    }
  } catch(e) {}
}

// Filter to new grants only
const newGrants = allGrants.filter(g => {
  const oppNum = (g.oppNum || '').trim();
  const title = (g.title || '').trim();
  if (oppNum && existingIds.has(oppNum)) return false;
  if (!oppNum && title && existingTitles.has(title)) return false;
  return true;
});

// --- STEP 2: If no new grants, mark done and exit ---
if (newGrants.length === 0) {
  try {
    await writeSearchResult.call(this, {
      search_id: searchId,
      org_id: orgId,
      source_group: '__done__',
      grant_data: [],
      is_complete: true,
    });
  } catch(e) {}
  return [{ json: { success: true, message: 'No new grants found', totalMatched: 0 } }];
}

// --- STEP 3: Process grants in AI batches ---
const totalBatches = Math.ceil(newGrants.length / AI_BATCH);
let totalMatched = 0;
const allMatched = [];

const systemPrompt = `You are a grant relevance filter. You receive a search query, optional filters, and a list of grants. Your job is to decide which
grants are genuinely relevant to the user's search.

FILTERING RULES:
1. Analyze the search query to understand the specific domain, topic, and intent.
2. Keep a grant ONLY if its Title or Description directly relates to the query's core topic.
3. Discard a grant if the connection to the search query requires more than one logical hop or is only tangential.
4. When in doubt, DISCARD. Users prefer fewer, highly relevant results over many loosely related ones.

ADDITIONAL FILTERS (apply only if the value is provided and not "Any" or empty):
- Organization Type: Only keep grants whose eligible applicants include this org type.
- Nonprofit/For-Profit Status: If "Nonprofit", discard grants only for for-profits. If "For-Profit", discard grants only for nonprofits. If "Either" or
empty, skip.
- Industry/Sector: Only keep grants relevant to this sector. Use semantic matching.
- Funding Category: "Federal Grant" = only federal. "Foundation / Private Grant" = only philanthropic/foundation. If empty, skip.
- Geographic Focus: If provided, only keep grants whose eligibility includes this geographic area.

Return ONLY a valid JSON object with two properties:
- "ids": array of IDs of grants that pass ALL filters
- "no_results": boolean, true if no grants matched

Example with matches: {"ids": ["361204", "358858", "352411"], "no_results": false}
Example with no matches: {"ids": [], "no_results": true}

Do NOT return markdown or explanation. Just the JSON object.`;

for (let b = 0; b < totalBatches; b++) {
  const start = b * AI_BATCH;
  const batch = newGrants.slice(start, start + AI_BATCH);
  const grantsSoFar = start + batch.length;

  // Post status update
  try {
    await writeSearchResult.call(this, {
      search_id: searchId,
      org_id: orgId,
      source_group: '__status__:filtering',
      grant_data: { status: 'filtering', stage_message: 'Matching ' + grantsSoFar + ' of ' + newGrants.length + ' grants to your search...' },
      is_complete: false,
    });
  } catch(e) {}

  // Build user prompt
  const grantsForAI = batch.map(g => ({
    id: g.oppNum || g.id || '',
    title: g.title || '',
    description: (g.description || '').substring(0, 500),
    agency: g.agency || ''
  }));

  const userPrompt = `Search Query: ${searchQuery}

Filters:
- Organization Type: ${orgType}
- Nonprofit/For-Profit: ${profitStatus}
- Industry/Sector: ${industry}
- Funding Category: ${fundingCategory}

Grants to evaluate:
${JSON.stringify(grantsForAI, null, 2)}`;

  // Call OpenAI API
  let keepIds = [];
  try {
    const aiResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Authorization': 'Bearer ' + openAiKey,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: 'gpt-4.1-mini',
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt }
        ],
        temperature: 0,
      }),
    });

    const aiText = aiResponse.choices?.[0]?.message?.content || '{}';
    const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(cleaned);
    keepIds = Array.isArray(parsed) ? parsed : (parsed.ids || []);
    keepIds = keepIds.map(String);
  } catch(e) {
    keepIds = [];
  }

  // Filter and save matched grants
  const matched = batch.filter(g => {
    const grantId = String(g.oppNum || g.id || '');
    return keepIds.includes(grantId);
  });

  if (matched.length > 0) {
    totalMatched += matched.length;
    const grantData = matched.map(g => ({ ...g, funder_name: g.agency || g.funder_name || 'Unknown' }));
    allMatched.push(...grantData);

    try {
      await writeSearchResult.call(this, {
        search_id: searchId,
        org_id: orgId,
        source_group: 'ai_filtered_' + b,
        grant_data: grantData,
        is_complete: false,
      });
    } catch(e) {}
  }
}

// --- STEP 4: Mark search complete ---
   const lastSourceDone = await isLastSourceDone.call(this, searchId);
  if (lastSourceDone) {
    try {
      await writeSearchResult.call(this, {
        search_id: searchId,
        org_id: orgId,
        source_group: '__done__',
        grant_data: [],
        is_complete: true,
      });
    } catch(e) {}
  }

  return allMatched.map(g => ({ json: g }));

const items = $input.all();

  if (items.length === 1 && (items[0].json.noResults || items[0].json.noNewGrants)) {
    return items;
  }

  function extractDate(grant) {
    const candidates = [
      grant.closeDate,
      grant.deadline,
      grant.dueDate,
      grant.due_date,
      grant.endDate,
      grant.end_date,
      grant.applicationDeadline,
      grant.application_deadline,
    ];

    for (const val of candidates) {
      if (!val || typeof val !== 'string') continue;
      const parsed = new Date(val);
      if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
        return parsed;
      }
    }

    if (grant.description) {
      const match = grant.description.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(\w+ \d{1,2},? \d{4})/);
      if (match) {
        const parsed = new Date(match[0]);
        if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
          return parsed;
        }
      }
    }

    return null;
  }

  const withDeadline = [];
  const noDeadline = [];

  for (const item of items) {
    const date = extractDate(item.json);
    if (date) {
      item._sortDate = date;
      withDeadline.push(item);
    } else {
      noDeadline.push(item);
    }
  }

  withDeadline.sort((a, b) => a._sortDate - b._sortDate);

  const combined = [...withDeadline, ...noDeadline];
  return combined.map(item => ({ json: item.json }));

// CA Grants Portal Scraper
// Paginates through search results for open grants, then scrapes each detail page
const grants = [];
const allGrantUrls = [];

// Step 1: Paginate through search results to collect all grant URLs
for (let page = 1; page <= 10; page++) {
  try {
    const html = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.grants.ca.gov/?s=&grant_status=open&paged=' + page,
      headers: { 'User-Agent': 'Mozilla/5.0' },
    });
    if (typeof html !== 'string') break;
    const links = html.match(/href="(https:\/\/www\.grants\.ca\.gov\/grants\/[^"]+)"/g) || [];
    const pageUrls = links.map(l => l.match(/href="([^"]+)"/)[1]).filter((v, i, a) => a.indexOf(v) === i);
    if (pageUrls.length === 0) break;
    allGrantUrls.push(...pageUrls);
  } catch(e) { break; }
}

// Deduplicate URLs
const uniqueUrls = [...new Set(allGrantUrls)];

// Step 2: Fetch each grant detail page and extract data
for (const url of uniqueUrls) {
  try {
    const html = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'User-Agent': 'Mozilla/5.0' },
    });
    if (typeof html !== 'string') continue;

    // Extract title
    const titleMatch = html.match(/<h1[^>]*>([^<]+)<\/h1>/i);
    const title = titleMatch ? titleMatch[1].trim() : '';
    if (!title) continue;

    // Extract grantor/agency
    const agencyMatch = html.match(/[Gg]rantor[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i)
      || html.match(/[Aa]gency[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i);
    const agency = agencyMatch ? agencyMatch[1].replace(/&amp;/g, '&').trim() : 'California State';

    // Extract description from paragraphs
    const descMatch = html.match(/[Dd]escription[^<]*<\/(?:h[2-4]|dt|th|strong)>\s*(?:<[^>]+>)*\s*([\s\S]*?)(?=<\/div>|<h[2-4]|<dt)/i);
    let description = '';
    if (descMatch) {
      description = descMatch[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim().substring(0, 1000);
    }
    if (!description) {
      const paragraphs = html.match(/<p[^>]*>([\s\S]*?)<\/p>/gi) || [];
      description = paragraphs.slice(0, 3).map(p => p.replace(/<[^>]+>/g, '').trim()).filter(p => p.length > 30).join(' ').substring(0, 1000);
    }

    // Extract deadline
    let deadline = 'See listing';
    const deadlineMatch = html.match(/[Dd]eadline[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i)
      || html.match(/[Cc]lose[^<]*[Dd]ate[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i)
      || html.match(/([\d]{1,2}\/[\d]{1,2}\/[\d]{2,4})\s*(?:at|by)/i);
    if (deadlineMatch && deadlineMatch[1]) {
      deadline = deadlineMatch[1].trim();
    }

    // Extract funding amounts
    let awardFloor = 0;
    let awardCeiling = 0;
    const amountMatches = html.match(/\$([\d,]+(?:\.\d{2})?)/g) || [];
    const amounts = amountMatches.map(a => parseInt(a.replace(/[$,]/g, ''))).filter(a => !isNaN(a) && a > 0 && a < 1000000000);
    if (amounts.length > 0) {
      awardFloor = Math.min(...amounts);
      awardCeiling = Math.max(...amounts);
    }

    // Extract eligibility
    let eligibility = '';
    const eligMatch = html.match(/[Ee]ligib[a-z]*[^<]*<\/(?:h[2-4]|dt|th|strong|b)>\s*(?:<[^>]+>)*\s*([\s\S]*?)(?=<\/div>|<h[2-4]|<dt)/i);
    if (eligMatch) {
      eligibility = eligMatch[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim().substring(0, 500);
    }

    // Extract category
    const catMatch = html.match(/[Cc]ategor[a-z]*[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i);
    const category = catMatch ? catMatch[1].trim() : 'State - California';

    // Generate stable oppNum from URL slug
    const slug = url.replace('https://www.grants.ca.gov/grants/', '').replace(/\/$/, '');
    const oppNum = 'CA-' + slug;

    grants.push({
      json: {
        id: oppNum,
        oppNum: oppNum,
        title: title,
        description: description || ('California state grant. Visit ' + url + ' for full details.'),
        link: url,
        openDate: new Date().toISOString().split('T')[0],
        closeDate: deadline,
        agency: agency,
        agencyCode: '',
        category: category,
        source: 'CA Grants Portal',
        awardFloor: awardFloor,
        awardCeiling: awardCeiling,
        status: 'posted',
        metadata: {
          eligibility: eligibility || null,
          sourceLevel: 'state',
          state: 'California'
        }
      }
    });
  } catch(e) {
    // Skip failed pages
  }
}

return grants.length > 0 ? grants : [{ json: { empty: true, source: 'ca-grants' } }];

// Extract grants from Grants.gov search2 API response
const items = $input.all();
const grants = [];

for (const item of items) {
  const response = item.json;

  let oppHits = [];
  if (response.data && response.data.oppHits) {
    oppHits = response.data.oppHits;
  } else if (response.oppHits) {
    oppHits = response.oppHits;
  } else if (Array.isArray(response)) {
    oppHits = response;
  }

  for (const opp of oppHits) {
    if (!opp || !opp.title) continue;

    const oppNum = opp.number || opp.opportunityNumber || 'GG-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);
    const oppId = opp.id || opp.opportunityId;

    let description = '';
    let awardCeiling = parseInt(opp.awardCeiling) || 0;
    let awardFloor = parseInt(opp.awardFloor) || 0;
    let eligibility = '';
    let additionalEligibility = '';
    let estimatedFunding = '';
    let costSharing = '';
    let categoryOfFunding = '';
    let closeDate = opp.closeDate || 'See listing';
    let postedDate = opp.openDate || opp.postedDate || '';
    let cfdaNumbers = opp.cfdaList || [];
    let numberOfAwards = '';
    let fundingInstruments = '';
    let contactInfo = '';
    let archiveDate = '';
    let responseDateDesc = '';
    let fundingDescLink = '';

    // Fetch full details from Grants.gov REST API
    if (oppId) {
      try {
        const detail = await this.helpers.httpRequest({
          method: 'POST',
          url: 'https://apply07.grants.gov/grantsws/rest/opportunity/details',
          headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
          body: 'oppId=' + oppId,
        });

        // --- Synopsis section (posted grants) ---
        if (detail && detail.synopsis) {
          const syn = detail.synopsis;
          description = (syn.synopsisDesc || '').replace(/<[^>]+>/g, '').trim();
          const ceil = parseInt(syn.awardCeiling);
          const floor = parseInt(syn.awardFloor);
          if (!isNaN(ceil)) awardCeiling = ceil;
          if (!isNaN(floor)) awardFloor = floor;
          estimatedFunding = syn.estimatedFunding || '';
          costSharing = syn.costSharing ? 'Yes' : 'No';
          numberOfAwards = syn.numberOfAwards || '';
          if (syn.responseDate) closeDate = syn.responseDate;
          responseDateDesc = syn.responseDateDesc || '';
          if (syn.postingDate) postedDate = syn.postingDate;
          archiveDate = syn.archiveDate || '';
          fundingDescLink = syn.fundingDescLinkUrl || '';
          if (syn.agencyContactDesc) contactInfo = syn.agencyContactDesc;
          if (syn.agencyContactEmail) contactInfo += ' | ' + syn.agencyContactEmail;
          if (syn.applicantTypes && syn.applicantTypes.length > 0) {
            eligibility = syn.applicantTypes.map(t => t.description).join('; ');
          }
          additionalEligibility = syn.applicantEligibilityDesc || '';
          if (syn.fundingActivityCategories && syn.fundingActivityCategories.length > 0) {
            categoryOfFunding = syn.fundingActivityCategories.map(c => c.description).join('; ');
          }
          if (syn.fundingInstruments && syn.fundingInstruments.length > 0) {
            fundingInstruments = syn.fundingInstruments.map(f => f.description).join('; ');
          }
        }

        // --- Forecast section (forecasted grants) ---
        if (detail && detail.forecast) {
          const fc = detail.forecast;
          if (!description) {
            description = (fc.forecastDesc || fc.description || '').replace(/<[^>]+>/g, '').trim();
          }
          if (!estimatedFunding && fc.estimatedFunding) estimatedFunding = fc.estimatedFunding;
          if (!costSharing && fc.costSharing != null) costSharing = fc.costSharing ? 'Yes' : 'No';
          if (!numberOfAwards && fc.numberOfAwards) numberOfAwards = fc.numberOfAwards;
          if (closeDate === 'See listing' && fc.estimatedApplicationDueDate) closeDate = fc.estimatedApplicationDueDate;
          if (!postedDate && fc.estimatedPostDate) postedDate = fc.estimatedPostDate;
          if (!archiveDate && fc.archiveDate) archiveDate = fc.archiveDate;
          if (!fundingDescLink && fc.fundingDescLinkUrl) fundingDescLink = fc.fundingDescLinkUrl;
          if (!contactInfo && fc.agencyContactDesc) {
            contactInfo = fc.agencyContactDesc;
            if (fc.agencyContactEmail) contactInfo += ' | ' + fc.agencyContactEmail;
          }
          if (!eligibility && fc.applicantTypes && fc.applicantTypes.length > 0) {
            eligibility = fc.applicantTypes.map(t => t.description).join('; ');
          }
          if (!additionalEligibility && fc.applicantEligibilityDesc) {
            additionalEligibility = fc.applicantEligibilityDesc;
          }
          if (!categoryOfFunding && fc.fundingActivityCategories && fc.fundingActivityCategories.length > 0) {
            categoryOfFunding = fc.fundingActivityCategories.map(c => c.description).join('; ');
          }
          if (!fundingInstruments && fc.fundingInstruments && fc.fundingInstruments.length > 0) {
            fundingInstruments = fc.fundingInstruments.map(f => f.description).join('; ');
          }
          const ceil = parseInt(fc.awardCeiling);
          const floor = parseInt(fc.awardFloor);
          if (awardCeiling === 0 && !isNaN(ceil)) awardCeiling = ceil;
          if (awardFloor === 0 && !isNaN(floor)) awardFloor = floor;
        }

        if (detail.cfdas && detail.cfdas.length > 0) {
          cfdaNumbers = detail.cfdas.map(c => c.cfdaNumber + ' -- ' + (c.programTitle || ''));
        }
      } catch(e) {
        // API fetch failed, continue with basic data
      }
    }

    grants.push({
      json: {
        id: oppId,
        oppNum: oppNum,
        title: opp.title,
        description: description || (opp.synopsis || opp.description || ''),
        link: 'https://www.grants.gov/search-results-detail/' + oppId,
        openDate: postedDate,
        closeDate: closeDate,
        agency: opp.agency || opp.agencyName || '',
        agencyCode: opp.agencyCode || '',
        category: opp.category || '',
        source: 'Grants.gov',
        awardFloor: awardFloor,
        awardCeiling: awardCeiling,
        status: opp.oppStatus || opp.status || '',
