const grants = [];

for (const program of grantPrograms) {
  const url = 'https://dced.pa.gov/programs/' + program.slug + '/';
  let description = '';
  let eligibility = '';
  let awardFloor = 0;
  let awardCeiling = 0;
  let deadline = 'See program guidelines';

  try {
    const html = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'User-Agent': 'Mozilla/5.0' },
      returnFullResponse: false,
    });

    if (typeof html === 'string') {
      // Extract description from entry-content or main content area
      const descMatch = html.match(/<div[^>]*class="[^"]*entry-content[^"]*"[^>]*>([\s\S]*?)<\/div>/i)
        || html.match(/<div[^>]*class="[^"]*program-description[^"]*"[^>]*>([\s\S]*?)<\/div>/i)
        || html.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
      if (descMatch) {
        // Get text from first few paragraphs
        const paragraphs = descMatch[1].match(/<p[^>]*>([\s\S]*?)<\/p>/gi) || [];
        description = paragraphs.slice(0, 3)
          .map(p => p.replace(/<[^>]+>/g, '').trim())
          .filter(p => p.length > 20)
          .join(' ');
      }

      // Extract eligibility
      const eligMatch = html.match(/[Ee]ligib[a-z]*[^<]*<\/(?:h[2-4]|strong|b)>\s*(?:<[^>]+>)*\s*([\s\S]*?)(?=<\/div>|<h[2-4])/i);
      if (eligMatch) {
        eligibility = eligMatch[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim().substring(0, 500);
      }

      // Extract funding amounts
      const amountMatch = html.match(/\$([\d,]+(?:\.\d{2})?)/g);
      if (amountMatch) {
        const amounts = amountMatch.map(a => parseInt(a.replace(/[$,]/g, ''))).filter(a => !isNaN(a) && a > 0);
        if (amounts.length > 0) {
          awardFloor = Math.min(...amounts);
          awardCeiling = Math.max(...amounts);
        }
      }

      // Extract deadline
      const deadlineMatch = html.match(/[Dd]eadline[^<]*(?:<[^>]+>)*\s*([^<]+)/)
        || html.match(/[Aa]pplications?\s+(?:must be|are due|due by|accepted until)[^<]*([^<]+)/)
        || html.match(/[Ss]ubmit(?:ted)? by\s+([A-Z][a-z]+ \d{1,2}(?:,? \d{4})?)/i);
      if (deadlineMatch) {
        deadline = deadlineMatch[1] ? deadlineMatch[1].replace(/<[^>]+>/g, '').trim() : deadline;
        if (deadline.length > 100) deadline = deadline.substring(0, 100);
      }
    }
  } catch(e) {
    // Page fetch failed, use basic data
  }

  const oppNum = 'PA-DCED-' + program.slug;

  grants.push({
    json: {
      id: oppNum,
      oppNum: oppNum,
      title: 'Pennsylvania: ' + program.name,
      description: description || ('PA DCED grant program. Visit ' + url + ' for full details.'),
      link: url,
      openDate: new Date().toISOString().split('T')[0],
      closeDate: deadline,
      agency: 'PA Dept of Community & Economic Development',
      agencyCode: 'PA-DCED',
      category: 'State Grant',
      source: 'Pennsylvania DCED',
      awardFloor: awardFloor,
      awardCeiling: awardCeiling,
      status: 'posted',
      metadata: {
        eligibility: eligibility || null,
        sourceLevel: 'state',
        state: 'Pennsylvania'
      }
    }
  });
}

